export interface ServiceCardProps {
  title: string;
  description: string;
  icon: React.ReactNode;
  image: string;
}

export interface Testimonial {
  name: string;
  text: string;
  rating: number;
  location: string;
}

export interface QuoteRequest {
  rooms: number;
  bathrooms: number;
  sqft: number;
  type: 'standard' | 'deep' | 'move';
  extras: string[];
}

export interface QuoteResponse {
  estimatedPrice: string;
  duration: string;
  recommendation: string;
}

import { GoogleGenAI, Type } from "@google/genai";
import { QuoteRequest, QuoteResponse } from "../types";

const API_KEY = process.env.API_KEY || "";

export const getAIQuote = async (request: QuoteRequest): Promise<QuoteResponse> => {
  if (!API_KEY) {
    // Fallback for demo if API key is missing
    return {
      estimatedPrice: `$${(request.rooms * 40 + request.bathrooms * 30 + request.sqft * 0.05).toFixed(2)}`,
      duration: `${Math.ceil(request.rooms * 0.5 + request.bathrooms * 0.75)} hours`,
      recommendation: "Our standard professional cleaning is perfect for your space!"
    };
  }

  const ai = new GoogleGenAI({ apiKey: API_KEY });

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `Estimate cleaning cost for: ${JSON.stringify(request)}. 
    Base price: $100. 
    Standard: $30/room, $40/bath. 
    Deep: +50%. 
    Move: +75%. 
    Extras: $20 each.`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          estimatedPrice: { type: Type.STRING },
          duration: { type: Type.STRING },
          recommendation: { type: Type.STRING }
        },
        required: ["estimatedPrice", "duration", "recommendation"]
      }
    }
  });

  return JSON.parse(response.text || "{}") as QuoteResponse;
};

