                    <p className="text-sm italic text-blue-200 leading-relaxed">
                      " {quote?.recommendation} "
                    </p>
                  </div>
                </div>

                <button 
                  onClick={handleBooking}
                  className="w-full py-4 bg-white text-slate-900 rounded-xl font-bold hover:bg-blue-50 transition-all shadow-lg hover:shadow-xl hover:-translate-y-1"
                >
                  Proceed to Booking
                </button>
                <p className="text-center text-xs text-slate-500">Prices may vary based on actual home condition.</p>
              </div>
            )}
          </div>
        </Reveal>
      </div>
    </section>
  );
};

