import { Home, Bath, Square, Loader2, Sparkles, CheckCircle, Calendar, Clock, User, Mail, Phone, ArrowRight, ArrowLeft, Confetti } from 'lucide-react';
import Reveal from './Reveal';

type Step = 'input' | 'quote' | 'schedule' | 'details' | 'success';

const QuoteEstimator: React.FC = () => {
  const [step, setStep] = useState<Step>('input');
  const [loading, setLoading] = useState(false);
  const [quote, setQuote] = useState<QuoteResponse | null>(null);

  // Form Data
  const [formData, setFormData] = useState<QuoteRequest>({
    rooms: 2,
    bathrooms: 2,
    sqft: 1500,
    type: 'standard',
    extras: []
  });

  // Booking Data
  const [bookingDate, setBookingDate] = useState('');
  const [bookingTime, setBookingTime] = useState('');
  const [contactInfo, setContactInfo] = useState({ name: '', email: '', phone: '' });

  const getNextDays = () => {
    const dates = [];
    for (let i = 1; i <= 5; i++) {
      const d = new Date();
      d.setDate(d.getDate() + i);
      dates.push(d);
    }
    return dates;
  };

  const handleQuoteSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    try {
      const result = await getAIQuote(formData);
      setQuote(result);
      setStep('quote');
    } catch (error) {
      console.error(error);
    } finally {
      setLoading(false);
    }
  };

  const handleScheduleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (bookingDate && bookingTime) setStep('details');
  };

  const handleFinalBooking = (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    // Simulate API booking
    setTimeout(() => {
      setLoading(false);
      setStep('success');
    }, 2000);
  };

  const toggleExtra = (extra: string) => {
    setFormData(prev => ({
      ...prev,
      extras: prev.extras.includes(extra) 
        ? prev.extras.filter(e => e !== extra)
        : [...prev.extras, extra]
